import React, { useRef, useEffect, useState } from "react";
import "./App.css";

const getDimensions = ele => {
  const { height } = ele.getBoundingClientRect();
  const offsetTop = ele.offsetTop;
  const offsetBottom = offsetTop + height;

  return {
    height,
    offsetTop,
    offsetBottom,
  };
};

const scrollTo = ele => {
  ele.scrollIntoView({
    behavior: "smooth",
    block: "start",
  });
};

function App() {
  const [visibleSection, setVisibleSection] = useState();

  const headerRef = useRef(null);
  const introRef = useRef(null);
  const projectRef = useRef(null);
  const contactRef = useRef(null);

  const sectionRefs = [
    { section: "Introduction", ref: introRef },
    { section: "Projects", ref: projectRef },
    { section: "Contact", ref: contactRef },
  ];

  useEffect(() => {
    const handleScroll = () => {
      const { height: headerHeight } = getDimensions(headerRef.current);
      const scrollPosition = window.scrollY + headerHeight;

      const selected = sectionRefs.find(({ section, ref }) => {
        const ele = ref.current;
        if (ele) {
          const { offsetBottom, offsetTop } = getDimensions(ele);
          return scrollPosition > offsetTop && scrollPosition < offsetBottom;
        }
      });

      if (selected && selected.section !== visibleSection) {
        setVisibleSection(selected.section);
      } else if (!selected && visibleSection) {
        setVisibleSection(undefined);
      }
    };

    handleScroll();
    window.addEventListener("scroll", handleScroll);
    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, [visibleSection]);

  return (
    <div className="App">
      <div className="top-spacer" />

      <div className="content">
        <div className="sticky">
          <div className="header" ref={headerRef}>
            <button
              type="button"
              className={`header_link ${visibleSection === "Introduction" ? "selected" : ""}`}
              onClick={() => {
                scrollTo(introRef.current);
              }}
            >
              Introduction
            </button>
            <button
              type="button"
              className={`header_link ${visibleSection === "Projects" ? "selected" : ""}`}
              onClick={() => {
                scrollTo(projectRef.current);
              }}
            >
              Projects
            </button>
            <button
              type="button"
              className={`header_link ${visibleSection === "Contact" ? "selected" : ""}`}
              onClick={() => {
                scrollTo(contactRef.current);
              }}
            >
              Contact
            </button>
          </div>
        </div>
        <div className="section" id="Introduction" ref={introRef}>
          <h2 id="name">Benny Nguyen</h2>
          <a href='../nguyenbenny_resume.pdf'>Link to my Resume.</a>
          <p>
            I am a recent Ph.D. graduate from the <a href="https://cogsci.ucmerced.edu/">Cogntive and Information Sciences Department</a> at the University of California, Merced.<br></br><br></br>
            I was advised by <a href="https://ucmerced.academia.edu/MichaelSpivey">Dr. Michael J. Spivey</a> on my thesis examining the complexity matching of gesture and gaze between a human listener and speaking virtual agent(s).<br></br><br></br>
            While in graduate school, I spent a summer as a <a href="https://codingitforward.com/fellowship">Civic Digital Fellow</a> working at the <a href="https://allofus.nih.gov/">National Institutes of Health, All of Us Research Program.</a><br></br><br></br>
            Prior to graduate school, I received my Bachelor’s degree in Psychology from <a href="https://www.grinnell.edu/">Grinnell College</a> and worked briefly at the University of Michigan's <a href="https://studentlife.umich.edu/">Student Life Assessment and Research Office</a>.<br></br><br></br>
            At Grinnell, I did internships at <a href="https://mpulse.com/">mPulse Mobile</a> (personalized healthcare text messaging service company in Los Angeles) and <a href="https://www.act.org/">ACT, Inc.</a> (testing company), and worked with <a href="https://www.grinnell.edu/user/ralstonc">Dr. Christopher Ralston</a> on refining a scale for assessing juvenile sexual offense recidivism.
            <br></br><br></br>
            I am currently looking for a position in industry where I can continue to use and develop my scientific skills (ideation, experimentation, measurement, evaluation, quantitative and qualitative methods, written and oral communication). Across these various roles I have acquired many technical skills including, but not limited to, Python, R, MATLAB, HTML, CSS, C#, Stata, SPSS, longitudinal time series analyses, natural language processing, and both Bayesian and Frequentist statistics. <br></br>
            Many of these skills are showcased in the Projects section below.
          </p>




        </div>
        <div className="section" id="Projects" ref={projectRef}>

        </div>
        <div className="section" id="Contact" ref={contactRef}>

        </div>
      </div>

      <div className="bottom-spacer" />
    </div>
  );
}

export default App;
